const { parseOpenApi, getBaseUrl } = require\('./dist/parser/swagger.js'\);
const { generateTools } = require\('./dist/converter/tool-generator.js'\);
const { ApiRegistry } = require\('./dist/registry/api-registry.js'\);
const { executeApiDetail } = require\('./dist/tools/discovery/api-detail.js'\);

async function test\(\) {
  const doc = await parseOpenApi\('https://petstore3.swagger.io/api/v3/openapi.json'\);
  const tools = generateTools\(doc.operations, doc.components?.schemas\);
  const registry = new ApiRegistry\(\);
  for \(const tool of tools\) {
    registry.register\({
      id: tool.operation.operationId || tool.name,
      name: tool.name,
      method: tool.operation.method,
      path: tool.operation.path,
      summary: tool.operation.summary,
      description: tool.operation.description,
      tags: tool.operation.tags,
      deprecated: tool.operation.deprecated,
      operation: tool.operation,
      components: doc.components?.schemas,
    }\);
  }
  const result = executeApiDetail\(registry, { id: 'addPet' }\);
  console.log\(result\);
}
test\(\).catch\(err => console.error\('ERROR:', err.message, err.stack\)\);
" 2>&1)

